## NuGet Packages

```
dotnet add package OpenTelemetry.Extensions.Hosting
dotnet add package OpenTelemetry.Instrumentation.AspNetCore
dotnet add package OpenTelemetry.Instrumentation.Http
dotnet add package OpenTelemetry.Exporter.OpenTelemetryProtocol
```

## Program.cs

```csharp
using OpenTelemetry.Logs;
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "MyService";
var serviceVersion = "1.0.0";

// Shared resource for all signals
var resource = ResourceBuilder.CreateDefault()
    .AddService(serviceName: serviceName, serviceVersion: serviceVersion);

// --- Traces ---
builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(serviceName, serviceVersion: serviceVersion))
    .WithTracing(tracing =>
    {
        tracing
            .AddAspNetCoreInstrumentation()
            .AddHttpClientInstrumentation()
            .AddOtlpExporter(opts =>
            {
                opts.Endpoint = new Uri("http://localhost:4317");
            });
    })
    // --- Metrics ---
    .WithMetrics(metrics =>
    {
        metrics
            .AddAspNetCoreInstrumentation()
            .AddHttpClientInstrumentation()
            .AddRuntimeInstrumentation()
            .AddOtlpExporter(opts =>
            {
                opts.Endpoint = new Uri("http://localhost:4317");
            });
    });

// --- Logs ---
builder.Logging.AddOpenTelemetry(logging =>
{
    logging.SetResourceBuilder(resource);
    logging.IncludeFormattedMessage = true;
    logging.IncludeScopes = true;
    logging.AddOtlpExporter(opts =>
    {
        opts.Endpoint = new Uri("http://localhost:4317");
    });
});

var app = builder.Build();

app.MapGet("/", () => "Hello, OpenTelemetry!");

app.Run();
```

**Key points:**

- **Port 4317** is the default gRPC OTLP endpoint; use `4318` for HTTP/protobuf (and set `opts.Protocol = OtlpExportProtocol.HttpProtobuf`).
- `AddRuntimeInstrumentation()` requires `OpenTelemetry.Instrumentation.Runtime` if you want GC/threadpool metrics — add it with `dotnet add package OpenTelemetry.Instrumentation.Runtime`.
- The `OTEL_EXPORTER_OTLP_ENDPOINT` env var overrides the hardcoded URI, so in production you can skip the explicit `opts.Endpoint` assignment and configure via environment instead.
- Traces and metrics share `ConfigureResource` via the fluent `AddOpenTelemetry()` chain; logs need a separate `SetResourceBuilder` call because they hang off `builder.Logging`.
